import{_ as i,o as a,c as s,an as t}from"./chunks/framework.ubcH7j8_.js";const k=JSON.parse('{"title":"Adding a New Capability","description":"","frontmatter":{},"headers":[],"relativePath":"contributing/new-capability.md","filePath":"contributing/new-capability.md","lastUpdated":1773164166000}'),n={name:"contributing/new-capability.md"};function r(l,e,c,d,p,o){return a(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="adding-a-new-capability" tabindex="-1">Adding a New Capability <a class="header-anchor" href="#adding-a-new-capability" aria-label="Permalink to &quot;Adding a New Capability&quot;">​</a></h1><p>A capability is a named, opt-in group of services that can be activated by a tier preset or by an explicit entry in <code>arc.yaml</code>. Follow these six steps.</p><h2 id="checklist" tabindex="-1">Checklist <a class="header-anchor" href="#checklist" aria-label="Permalink to &quot;Checklist&quot;">​</a></h2><h3 id="_1-define-the-capability-name-and-its-required-services-in-services-profiles-yaml" tabindex="-1">1. Define the capability name and its required services in <code>services/profiles.yaml</code> <a class="header-anchor" href="#_1-define-the-capability-name-and-its-required-services-in-services-profiles-yaml" aria-label="Permalink to &quot;1. Define the capability name and its required services in \`services/profiles.yaml\`&quot;">​</a></h3><p>Add an entry under the <code>capabilities:</code> key. The name must be lowercase and kebab-case.</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">capabilities</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  my-capability</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    services</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">my-service-a</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">my-service-b</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;One-line description of what this capability provides&quot;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # requires: [other-capability]   # optional: list capabilities that must also be active</span></span></code></pre></div><p>Use <code>requires</code> when your capability depends on another (e.g., <code>voice</code> requires <code>reasoner</code> because the voice agent calls the LLM bridge).</p><h3 id="_2-add-the-capability-s-services-to-services-profiles-yaml" tabindex="-1">2. Add the capability&#39;s services to <code>services/profiles.yaml</code> <a class="header-anchor" href="#_2-add-the-capability-s-services-to-services-profiles-yaml" aria-label="Permalink to &quot;2. Add the capability&#39;s services to \`services/profiles.yaml\`&quot;">​</a></h3><p>Each service listed under <code>services:</code> must either already exist in the monorepo or be created as part of this change. For new services, follow <a href="./new-service.html">Adding a New Service</a> before returning to this step.</p><p>Verify that all referenced services have a <code>services/&lt;name&gt;/service.yaml</code> and a <code>Dockerfile</code>.</p><h3 id="_3-add-the-capability-to-the-appropriate-tier-preset-s-in-profiles-yaml" tabindex="-1">3. Add the capability to the appropriate tier preset(s) in <code>profiles.yaml</code> <a class="header-anchor" href="#_3-add-the-capability-to-the-appropriate-tier-preset-s-in-profiles-yaml" aria-label="Permalink to &quot;3. Add the capability to the appropriate tier preset(s) in \`profiles.yaml\`&quot;">​</a></h3><p>If the capability should be active for a standard tier, add it to the <code>capabilities:</code> list for that tier. The standard upgrade path is <code>think → reason → ultra-instinct</code>.</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">reason</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;Core + reasoning engine — standard development stack&#39;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  capabilities</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">reasoner</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">my-capability</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # add here if it belongs in reason and above</span></span></code></pre></div><p>If it is only relevant for <code>ultra-instinct</code>, the wildcard <code>capabilities: &#39;*&#39;</code> already covers it — no change to tier presets is needed.</p><h3 id="_4-test-locally" tabindex="-1">4. Test locally <a class="header-anchor" href="#_4-test-locally" aria-label="Permalink to &quot;4. Test locally&quot;">​</a></h3><p>Start the capability in isolation to verify the services come up and the health checks pass:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Start a specific tier that includes your capability</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PROFILE=reason</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Or start only the capability&#39;s services directly (if you know the compose service names)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev-health</span></span></code></pre></div><p>Check that all new services appear healthy in <code>make dev-health</code> output before proceeding.</p><h3 id="_5-write-docs-page-s-for-the-new-services-and-update-the-sidebar" tabindex="-1">5. Write docs page(s) for the new services and update the sidebar <a class="header-anchor" href="#_5-write-docs-page-s-for-the-new-services-and-update-the-sidebar" aria-label="Permalink to &quot;5. Write docs page(s) for the new services and update the sidebar&quot;">​</a></h3><p>For each new service the capability introduces, create a docs page under <code>docs/services/</code> (see step 6 of <a href="./new-service.html">Adding a New Service</a>). Then add all new pages to the Services sidebar in <code>docs/.vitepress/config.ts</code>.</p><p>If the capability itself warrants a concept page (e.g., explaining when to use it and what it costs), add a page under <code>docs/guide/</code> and link it from the sidebar.</p><h3 id="_6-write-an-ard-if-the-capability-introduces-new-architectural-decisions" tabindex="-1">6. Write an ARD if the capability introduces new architectural decisions <a class="header-anchor" href="#_6-write-an-ard-if-the-capability-introduces-new-architectural-decisions" aria-label="Permalink to &quot;6. Write an ARD if the capability introduces new architectural decisions&quot;">​</a></h3><p>If activating this capability introduces a new dependency type, a new communication pattern, or a constraint that future contributors need to know about, write an Architecture Decision Record in <code>docs/ard/</code>. Name it <code>CAPABILITY-&lt;NAME&gt;.md</code> (all caps) and follow the existing ARD format.</p><p>Update the <code>ardSidebar()</code> function in <code>docs/.vitepress/config.ts</code> to include the new file, so it appears in the Architecture section of the docs site.</p>`,24)])])}const y=i(n,[["render",r]]);export{k as __pageData,y as default};
